mapper.select:
SELECT t.* FROM task_item t WHERE t.parent_id IS NULL
AND t.status = #{status}
AND ( EXISTS ( SELECT 1 FROM task_item_assignee a WHERE a.task_id = t.id AND a.user_id = #{userId} AND a.deleted = 0 ) OR t.creator_id = #{userId} OR EXISTS ( SELECT 1 FROM task_follower f WHERE f.task_id = t.id AND f.user_id = #{userId} AND f.deleted = 0 ) OR ( t.list_id IS NOT NULL AND EXISTS ( SELECT 1 FROM task_list_member m INNER JOIN task_list l ON l.id = m.list_id AND l.deleted = 0 WHERE m.list_id = t.list_id AND m.user_id = #{userId} AND m.deleted = 0 AND l.archived = 0 ) ) ) ORDER BY t.create_time DESC
